```javascript
app.get('/api/users/:id', authenticate, async (req, res) => {
  // Only allow users to view their own data
  if (req.user.id !== parseInt(req.params.id, 10)) {
    return res.status(403).json({ error: 'Forbidden' });
  }
  // ... rest of code
});
```

